CREATE TABLE ege_users (id SERIAL PRIMARY KEY, email VARCHAR(255) UNIQUE NOT NULL, password_hash VARCHAR(255) NOT NULL, first_name VARCHAR(100) NOT NULL, last_name VARCHAR(100) NOT NULL, role VARCHAR(20) NOT NULL DEFAULT 'student', pd_consent BOOLEAN NOT NULL DEFAULT false, pd_consent_at TIMESTAMPTZ, is_active BOOLEAN NOT NULL DEFAULT true, total_score INT DEFAULT 0, created_at TIMESTAMPTZ NOT NULL DEFAULT NOW());